package common.src.org.apache.hive.common;

public class HiveCompat { private static Log LOG = LogFactory . getLog ( HiveCompat . class ) ; public enum CompatLevel { HIVE_0_12 ( "0.12" , 0 , 12 ) , HIVE_0_13 ( "0.13" , 0 , 13 ) ; public final String value ; public final int majorVersion ; public final int minorVersion ; CompatLevel ( String val , int majorVersion , int minorVersion ) { this . value = val ; this . majorVersion = majorVersion ; this . minorVersion = minorVersion ; } } public static final String DEFAULT_COMPAT_LEVEL = CompatLevel . HIVE_0_12 . value ; public static final String LATEST_COMPAT_LEVEL = getLastCompatLevel ( ) . value ; public static CompatLevel getCompatLevel ( HiveConf hconf ) { return getCompatLevel ( HiveConf . getVar ( hconf , HiveConf . ConfVars . HIVE_COMPAT ) ) ; } public static CompatLevel getCompatLevel ( String compatStr ) { if ( compatStr . equalsIgnoreCase ( "latest" ) ) { compatStr = LATEST_COMPAT_LEVEL ; } for ( CompatLevel cl : CompatLevel . values ( ) ) { if ( cl . value . equals ( compatStr ) ) { return cl ; } } LOG . error ( "Could not find CompatLevel for " + compatStr + ", using default of " + DEFAULT_COMPAT_LEVEL ) ; return getCompatLevel ( DEFAULT_COMPAT_LEVEL ) ; } private static CompatLevel getLastCompatLevel ( ) { CompatLevel [ ] compatLevels = CompatLevel . values ( ) ; return compatLevels [ compatLevels . length - 1 ] ; } }